/* on.standard.board.sampleboard.mergeSampleBoardList */
SELECT IFNULL(MAX(BOARD_SERNO), 0) + 1 FROM STB_T_BOARD_MNG
SELECT #{boardSerno}
INSERT INTO STB_T_BOARD_MNG ( BOARD_SERNO , TITL , CONTENT , REG_USER , REG_DATE , USE_YN , NTI_YN , RCMD_YN , RCMD_COUNT , NTI_STRT_DT , NTI_END_DT , ATCH_FILE_ID , OPEN_YN , SCRET_YN , TEMPCOL_1 , TEMPCOL_2 , TEMPCOL_3 , TEMPCOL_4 , TEMPCOL_5 , TEMPCOL_6 , TEMPCOL_7 , TEMPCOL_8 , TEMPCOL_9 , TEMPCOL_10 ) VALUES ( #{boardSerno} , #{boardTitl} , #{editerContent} , #{loginUserId} , NOW() , IFNULL(#{useYn}, 'Y') , IFNULL(#{ntiYn}, 'N') , IFNULL(#{rcmdYn}, 'N') , IFNULL(#{rcmdCount}, 0) , #{ntiStrtDt} , #{ntiEndDt} , #{atchFileId} , IFNULL(#{openYn}, 'Y') , IFNULL(#{scretYn}, 'N') , #{region} , #{careerLvl} , #{tempcol3} , #{tempcol4} , #{tempcol5} , #{tempcol6} , #{tempcol7} , #{tempcol8} , #{tempcol9} , 'standardboard' ) ON DUPLICATE KEY UPDATE TITL = VALUES(TITL) , CONTENT = VALUES(CONTENT) , UPD_USER = VALUES(UPD_USER) , UPD_DATE = NOW() , USE_YN = VALUES(USE_YN) , NTI_YN = VALUES(NTI_YN) , RCMD_YN = VALUES(RCMD_YN) , RCMD_COUNT = VALUES(RCMD_COUNT) , NTI_STRT_DT = VALUES(NTI_STRT_DT) , NTI_END_DT = VALUES(NTI_END_DT) , ATCH_FILE_ID = VALUES(ATCH_FILE_ID) , OPEN_YN = VALUES(OPEN_YN) , SCRET_YN = VALUES(SCRET_YN) , TEMPCOL_1 = VALUES(TEMPCOL_1) , TEMPCOL_2 = VALUES(TEMPCOL_2) , TEMPCOL_3 = VALUES(TEMPCOL_3) , TEMPCOL_4 = VALUES(TEMPCOL_4) , TEMPCOL_5 = VALUES(TEMPCOL_5) , TEMPCOL_6 = VALUES(TEMPCOL_6) , TEMPCOL_7 = VALUES(TEMPCOL_7) , TEMPCOL_8 = VALUES(TEMPCOL_8) , TEMPCOL_9 = VALUES(TEMPCOL_9)

mapper.update:
/* on.standard.board.sampleboard.deleteSampleBoard */
UPDATE STB_T_BOARD_MNG
  SET USE_YN = 'N'
    , UPD_USER     = #{loginUserId}
    , UPD_DATE     = NOW()
WHERE BOARD_SERNO = #{boardSerno}
  AND TEMPCOL_10 = 'standardboard'
